// Unicode Variation Sequences — IVD (CJK) + SVS (Standardized)
// Sources:
//   IVD: https://www.unicode.org/ivd/data/2022-09-13/IVD_Sequences.txt
//   SVS: https://www.unicode.org/Public/UCD/latest/ucd/StandardizedVariants.txt
// 15631 base characters, 30730 total sequences
// Encoding: 3 bytes base CP + 1 byte count + N bytes VS
//   IVS (U+E0100-E01EF): offset 0x00-0xEF
//   SVS (U+FE00-FE0F): offset 0xF0-0xFF

// prettier-ignore
const VS_DATA = "";

let vsBytes: Uint8Array | null = null;
let vsIndex: Map<number, number> | null = null;

function ensureVs() {
  if (vsBytes) return;
  const bin = atob(VS_DATA);
  vsBytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) vsBytes[i] = bin.charCodeAt(i);
  vsIndex = new Map();
  let offset = 0;
  while (offset < vsBytes.length) {
    const cp = (vsBytes[offset] << 16) | (vsBytes[offset + 1] << 8) | vsBytes[offset + 2];
    vsIndex.set(cp, offset);
    const count = vsBytes[offset + 3];
    offset += 4 + count;
  }
}

function readVariants(cp: number): number[] {
  ensureVs();
  const offset = vsIndex!.get(cp);
  if (offset === undefined) return [];
  const count = vsBytes![offset + 3];
  const variants: number[] = [];
  for (let i = 0; i < count; i++) {
    const b = vsBytes![offset + 4 + i];
    if (b <= 0xEF) variants.push(0xE0100 + b);
    else variants.push(0xFE00 + (b - 0xF0));
  }
  return variants;
}

/** Check if a VS code point is SVS (FE00-FE0F) or IVS (E0100-E01EF) */
export function isStandardizedVS(vs: number): boolean {
  return vs >= 0xFE00 && vs <= 0xFE0F;
}

/** Get total variation sequence count for a base code point. */
export function getVsCount(cp: number): number {
  ensureVs();
  const offset = vsIndex!.get(cp);
  if (offset === undefined) return 0;
  return vsBytes![offset + 3];
}

/** Get IVS-only count (E0100-E01EF). */
export function getIvsCount(cp: number): number {
  return readVariants(cp).filter(v => v >= 0xE0100).length;
}

/** Get SVS-only count (FE00-FE0F). */
export function getSvsCount(cp: number): number {
  return readVariants(cp).filter(v => v >= 0xFE00 && v <= 0xFE0F).length;
}

/** Get all variation selectors for a base code point. */
export function getAllVariants(cp: number): number[] {
  return readVariants(cp);
}

/** Get IVS-only variants (E0100-E01EF). */
export function getIvsVariants(cp: number): number[] {
  return readVariants(cp).filter(v => v >= 0xE0100);
}

/** Get SVS-only variants (FE00-FE0F). */
export function getSvsVariants(cp: number): number[] {
  return readVariants(cp).filter(v => v >= 0xFE00 && v <= 0xFE0F);
}

// Font glyph support: base characters where the font has actual
// different variant glyphs (not just default/None mappings).
// 5,195 base characters, 7,793 variant entries.
// Same encoding as VS_DATA.
// prettier-ignore
const FONT_GLYPH_DATA = "";

let fontGlyphBytes: Uint8Array | null = null;
let fontGlyphIndex: Map<number, number> | null = null;

function ensureFontGlyph() {
  if (fontGlyphBytes) return;
  const bin = atob(FONT_GLYPH_DATA);
  fontGlyphBytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) fontGlyphBytes[i] = bin.charCodeAt(i);
  fontGlyphIndex = new Map();
  let offset = 0;
  while (offset < fontGlyphBytes.length) {
    const cp = (fontGlyphBytes[offset] << 16) | (fontGlyphBytes[offset + 1] << 8) | fontGlyphBytes[offset + 2];
    fontGlyphIndex.set(cp, offset);
    const count = fontGlyphBytes[offset + 3];
    offset += 4 + count;
  }
}

/** Check if a specific base+VS combination has an actual different glyph in the font. */
export function hasFontGlyph(baseCp: number, vs: number): boolean {
  ensureFontGlyph();
  const offset = fontGlyphIndex!.get(baseCp);
  if (offset === undefined) return false;
  const count = fontGlyphBytes![offset + 3];
  for (let i = 0; i < count; i++) {
    const b = fontGlyphBytes![offset + 4 + i];
    const decoded = b <= 0xEF ? 0xE0100 + b : 0xFE00 + (b - 0xF0);
    if (decoded === vs) return true;
  }
  return false;
}

/** Count how many VS for a base character have actual different font glyphs. */
export function getFontGlyphCount(baseCp: number): number {
  ensureFontGlyph();
  const offset = fontGlyphIndex!.get(baseCp);
  if (offset === undefined) return 0;
  return fontGlyphBytes![offset + 3];
}
